import React, { useState, useEffect } from 'react';
import API from '../api/axios';

function AdminPage() {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    const fetchUsers = async () => {
      try {
        const { data } = await API.get('/admin/users');
        setUsers(data);
      } catch (err) { console.error(err); }
    };
    fetchUsers();
  }, []);

  const toggleStatus = async (userId) => {
    try {
      await API.put(`/admin/users/${userId}/status`);
      // Refresh list
      setUsers(users.map(u => u._id === userId ? { ...u, status: u.status === 'active' ? 'inactive' : 'active' } : u));
    } catch (err) { alert("Failed to update status"); }
  };

  return (
    <div style={{ padding: '2rem' }}>
      <h2>Admin Dashboard - User Management</h2>
      <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
        <thead>
          <tr style={{ background: '#ffb6c1' }}>
            <th style={{ padding: '10px', border: '1px solid #ddd' }}>Name</th>
            <th style={{ padding: '10px', border: '1px solid #ddd' }}>Status</th>
            <th style={{ padding: '10px', border: '1px solid #ddd' }}>Action</th>
          </tr>
        </thead>
        <tbody>
          {users.map(u => (
            <tr key={u._id} style={{ textAlign: 'center' }}>
              <td style={{ padding: '10px', border: '1px solid #ddd' }}>{u.name}</td>
              <td style={{ padding: '10px', border: '1px solid #ddd' }}>{u.status}</td>
              <td style={{ padding: '10px', border: '1px solid #ddd' }}>
                <button onClick={() => toggleStatus(u._id)} style={{ backgroundColor: u.status === 'active' ? '#ff4d4d' : '#4CAF50', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '5px', cursor: 'pointer' }}>
                  {u.status === 'active' ? 'Deactivate' : 'Activate'}
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default AdminPage;
